#include<bits/stdc++.h>
using namespace std;
int a[11][11];
int main() {
	int n, i = 1, j = 0, num = 1;
	cin >> n;
	while (num <= n * n) {

		while (a[i][++j] == 0 && j <= n) {
			a[i][j] = num++;
		}
		j--;
		while (a[++i][j] == 0 && i <= n) {
			a[i][j] = num++;
		}
		i--;
		while (a[i][--j] == 0 && j >= 1) {
			a[i][j] = num++;
		}
		j++;
		while (a[--i][j] == 0 && i >= 1) {
			a[i][j] = num++;
		}
		i++;
	}
	for (i = 1; i <=n; i++) {
		for (j = 1; j <= n; j++) {
			cout << setw(3) << setfill(' ') << a[i][j];

		}
		cout << endl;
	}
	return 0;
}
